 16→@Injectable()
 17→export class UserModel {
 18→	private readonly logger = new Logger(UserModel.name);
 19→	private readonly tableName = TABLE_NAME_USERS;
 20→
 21→	constructor(
 22→		@InjectConnection(KNEX_READ_CONNECTION) private readonly knexRead: Knex,
 23→		@InjectConnection(KNEX_WRITE_CONNECTION) private readonly knexWrite: Knex,
 24→	) {}
 25→
 26→	async findById({ userId }: { userId: IUserBase['_id'] }): Promise<IUserBase | null> {
 27→		try {
 28→			const result = await this.knexRead<IUserBase>(this.tableName)
 29→				.where({ _id: userId })
 30→				.whereNull('deleted_at')
 31→				.first();
 32→
 33→			if (!result) {
 34→				return null;
 35→			}
 36→
 37→			const dto = plainToInstance(UserBaseDto, result);
 38→			const errors = await validate(dto, { skipMissingProperties: true });
 39→			if (errors.length > 0) {
 40→				this.logger.error(
 41→					`Validation failed for user data: ${this.formatValidationErrors({ errors })}`,
 42→				);
 43→				throw new Error(`Validation failed: ${this.formatValidationErrors({ errors })}`);
 44→			}
 45→
 46→			return result;
 47→		} catch (error) {
 48→			this.logger.error(
 49→				`Failed to find user by id ${userId}: ${(error as Error).message}`,
 50→			);
 51→			throw error;
 52→		}
 53→	}
 54→
 55→	async findByEmail({ email }: { email: IUserBase['email'] }): Promise<IUserBase | null> {
 56→		try {
 57→			const result = await this.knexRead<IUserBase>(this.tableName)
 58→				.where({ email })
 59→				.whereNull('deleted_at')
 60→				.first();
 61→
 62→			if (!result) {
 63→				return null;
 64→			}
 65→
 66→			const dto = plainToInstance(UserBaseDto, result);
 67→			const errors = await validate(dto, { skipMissingProperties: true });
 68→			if (errors.length > 0) {
 69→				this.logger.error(
 70→					`Validation failed for user data: ${this.formatValidationErrors({ errors })}`,
 71→				);
 72→				throw new Error(`Validation failed: ${this.formatValidationErrors({ errors })}`);
 73→			}
 74→
 75→			return result;
 76→		} catch (error) {
 77→			this.logger.error(
 78→				`Failed to find user by email ${email}: ${(error as Error).message}`,
 79→			);
 80→			throw error;
 81→		}
 82→	}
 83→
 84→	async create({ data }: { data: IUserCreate }): Promise<IUserBase> {
 85→		try {
 86→			const dto = plainToInstance(UserBaseDto, data);
 87→			const errors = await validate(dto, { skipMissingProperties: true });
 88→			if (errors.length > 0) {
 89→				this.logger.error(
 90→					`Validation failed for user data: ${this.formatValidationErrors({ errors })}`,
 91→				);
 92→				throw new Error(`Validation failed: ${this.formatValidationErrors({ errors })}`);
 93→			}
 94→
 95→			const _id = randomUUID();
 96→			const [created] = await this.knexWrite<IUserBase>(this.tableName)
 97→				.insert({
 98→					_id,
 99→					...data,
100→					created_at: this.knexWrite.fn.now(),
101→					updated_at: this.knexWrite.fn.now(),
102→				})
103→				.returning('*');
104→
105→			if (!created) {
106→				throw new Error('Failed to create user');
107→			}
108→
109→			this.logger.debug(`Created user with id ${_id}`);
110→			return created;
111→		} catch (error) {
112→			this.logger.error(`Failed to create user: ${(error as Error).message}`);
113→			throw error;
114→		}
115→	}
116→
117→	async updateLastLogin({ userId }: { userId: IUserBase['_id'] }): Promise<void> {
118→		try {
119→			await this.knexWrite<IUserBase>(this.tableName)
120→				.where({ _id: userId })
121→				.whereNull('deleted_at')
122→				.update({
123→					last_login_at: this.knexWrite.fn.now(),
124→					updated_at: this.knexWrite.fn.now(),
125→				});
126→
127→			this.logger.debug(`Updated last login for user ${userId}`);
128→		} catch (error) {
129→			this.logger.error(
130→				`Failed to update last login for user ${userId}: ${(error as Error).message}`,
131→			);
132→			throw error;
133→		}
134→	}
135→
136→	async softDelete({ userId }: { userId: IUserBase['_id'] }): Promise<void> {
137→		try {
138→			await this.knexWrite<IUserBase>(this.tableName)
139→				.where({ _id: userId })
140→				.whereNull('deleted_at')
141→				.update({
142→					deleted_at: this.knexWrite.fn.now(),
143→					updated_at: this.knexWrite.fn.now(),
144→				});
145→
146→			this.logger.debug(`Soft deleted user ${userId}`);
147→		} catch (error) {
148→			this.logger.error(
149→				`Failed to soft delete user ${userId}: ${(error as Error).message}`,
150→			);
151→			throw error;
152→		}
153→	}
154→
155→	private formatValidationErrors({ errors }: { errors: ValidationError[] }): string {
156→		return errors
157→			.map(
158→				(error) =>
159→					`${error.property}: ${Object.values(error.constraints ?? {}).join(', ')}`,
160→			)
161→			.join('; ');
162→	}
163→}
