export interface ICompanyBase {
	_id: string;
	name: string;
	created_at: Date;
	updated_at: Date;
	deleted_at: Date | null;
}

import type { ICompanyBase } from '@modules/company/types/company.base.interface';

export type ICompanyCreate = Omit<
	ICompanyBase,
	'_id' | 'created_at' | 'updated_at' | 'deleted_at'
>;

import { IsDate, IsNotEmpty, IsOptional, IsString, IsUUID } from 'class-validator';

export class CompanyBaseDto {
	@IsUUID()
	@IsNotEmpty()
	_id: string;

	@IsString()
	@IsNotEmpty()
	name: string;

	@IsDate()
	@IsNotEmpty()
	created_at: Date;

	@IsDate()
	@IsNotEmpty()
	updated_at: Date;

	@IsOptional()
	@IsDate()
	deleted_at: Date | null;
}

import { OmitType } from '@nestjs/swagger';

import { CompanyBaseDto } from '@modules/company/dto/company.base.dto';

export class CompanyCreateDto extends OmitType(CompanyBaseDto, [
	'_id',
	'created_at',
	'updated_at',
	'deleted_at',
] as const) {}

import { Logger } from '@nestjs/common';
import { Test, TestingModule } from '@nestjs/testing';

